// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Define the structure for an edge
typedef struct Edge {
    int u, v, cost, param;
} Edge;

// Define the structure for a tree
typedef struct Tree {
    int n;
    Edge* edges;
} Tree;

// Function to calculate the minimum time required
int calculateMinTime(Tree* tree) {
    int n = tree->n;
    Edge* edges = tree->edges;
    int* depths = (int*) malloc(n * sizeof(int));
    int* costs = (int*) malloc(n * sizeof(int));
    int maxDepth = 0;
    int minTime = 0;

    // Calculate the depth of each node
    for (int i = 0; i < n; i++) {
        depths[i] = -1;
    }
    depths[0] = 0;
    for (int i = 0; i < n - 1; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        if (depths[u] != -1) {
            depths[v] = depths[u] + 1;
        }
    }

    // Calculate the cost of each node
    for (int i = 0; i < n; i++) {
        costs[i] = 0;
    }
    for (int i = 0; i < n - 1; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        costs[v] = costs[u] + edges[i].cost;
    }

    // Calculate the maximum depth
    for (int i = 0; i < n; i++) {
        if (depths[i] > maxDepth) {
            maxDepth = depths[i];
        }
    }

    // Calculate the minimum time required
    for (int i = 0; i < n - 1; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int cost = edges[i].cost;
        int param = edges[i].param;
        int diff = abs(cost - (maxDepth - depths[v]));
        minTime += diff * param;
    }

    free(depths);
    free(costs);
    return minTime;
}

int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int n;
        scanf("%d", &n);
        Tree tree;
        tree.n = n;
        tree.edges = (Edge*) malloc((n - 1) * sizeof(Edge));
        for (int j = 0; j < n - 1; j++) {
            int u, v, cost, param;
            scanf("%d %d %d %d", &u, &v, &cost, &param);
            tree.edges[j].u = u - 1;
            tree.edges[j].v = v - 1;
            tree.edges[j].cost = cost;
            tree.edges[j].param = param;
        }
        int minTime = calculateMinTime(&tree);
        printf("%d\n", minTime);
        for (int j = 0; j < n - 1; j++) {
            printf("%d\n", tree.edges[j].cost);
        }
        free(tree.edges);
    }
    return 0;
}

